import { useState, useEffect } from 'react';
import API from '../api/axios';

function AdminPage() {
  const [users, setUsers] = useState([]);
  const [posts, setPosts] = useState([]);
  const [tab, setTab] = useState('users');

  useEffect(() => {
    fetchUsers();
    fetchPosts();
  }, []);

  const fetchUsers = async () => {
    try {
      const { data } = await API.get('/admin/users');
      setUsers(data);
    } catch (err) {
      console.error('Failed to fetch users');
    }
  };

  const fetchPosts = async () => {
    try {
      const { data } = await API.get('/admin/posts');
      setPosts(data);
    } catch (err) {
      console.error('Failed to fetch posts');
    }
  };

  const toggleUserStatus = async (userId) => {
    try {
      const { data } = await API.put(`/admin/users/${userId}/status`);
      setUsers(users.map(u => u._id === userId ? data.user : u));
    } catch (err) {
      console.error('Failed to update user status');
    }
  };

  const removePost = async (postId) => {
    try {
      await API.put(`/admin/posts/${postId}/remove`);
      setPosts(posts.map(p => p._id === postId ? { ...p, status: 'removed' } : p));
    } catch (err) {
      console.error('Failed to remove post');
    }
  };

  return (
    <div className="admin-page container">
      <h2>Admin Dashboard</h2>
      
      <div className="admin-tabs">
        <button onClick={() => setTab('users')} className={tab === 'users' ? 'active' : ''}>
          Members ({users.length})
        </button>
        <button onClick={() => setTab('posts')} className={tab === 'posts' ? 'active' : ''}>
          All Posts ({posts.length})
        </button>
      </div>

      {tab === 'users' && (
        <table className="admin-table">
          <thead>
            <tr>
              <th>Name</th>
              <th>Email</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {users.map(user => (
              <tr key={user._id}>
                <td>{user.name}</td>
                <td>{user.email}</td>
                <td>
                  <span className={`status-badge ${user.status}`}>
                    {user.status}
                  </span>
                </td>
                <td>
                  <button
                    onClick={() => toggleUserStatus(user._id)}
                    className={user.status === 'active' ? 'btn-danger' : 'btn-success'}
                  >
                    {user.status === 'active' ? 'Deactivate' : 'Activate'}
                  </button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {tab === 'posts' && (
        <table className="admin-table">
          <thead>
            <tr>
              <th>Title</th>
              <th>Author</th>
              <th>Status</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {posts.map(post => (
              <tr key={post._id}>
                <td>{post.title}</td>
                <td>{post.author?.name}</td>
                <td>
                  <span className={`status-badge ${post.status}`}>
                    {post.status}
                  </span>
                </td>
                <td>
                  {post.status === 'published' && (
                    <button onClick={() => removePost(post._id)} className="btn-danger">
                      Remove
                    </button>
                  )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

export default AdminPage;
